// Solution.cpp
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int search(vector<int>& nums, int target) {
        int low = 0, high = nums.size() - 1;
        while (low <= high) {
            int mid = (low + high) / 2;
            if (nums[mid] == target) {
                return mid;
            } else if (nums[mid] < target) {
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        return -1;
    }
};

int main() {
    Solution solve;
    int arr[] = {-10, -9, -8, -7, -7};
    vector<int> vec(arr, arr + sizeof(arr) / sizeof(arr[0]));
    cout << solve.search(vec, -7) << endl;

    return 0;
}
